"use strict";exports.id=3134,exports.ids=[3134],exports.modules={13134:(a,b,c)=>{c.d(b,{AB:()=>n,Rs:()=>m,h9:()=>g,nu:()=>l});var d=c(74515),e=c(70373),f=c(87431);let g=["about","careers","press","premium","creator-program","terms","privacy","cookies","policy"],h={about:{slug:"about",badge:"Company",title:"Building the home for bold writers",subtitle:"ContentVerse is a creator-first publishing platform — built in India, for readers and writers who care about depth, design, and fair monetization in rupees.",sections:[{heading:"Our mission",paragraphs:["We started ContentVerse because great writing deserves more than a noisy feed and a broken payout model. Our goal is simple: help creators publish beautifully, grow an audience that actually reads, and earn in Indian Rupees — transparently.","From long-form essays and News in 60 shorts to polls, tips, and creator dashboards — every feature is designed around the writer’s studio, not the algorithm’s mood. We believe India’s internet deserves world-class editorial tools that respect both creators and readers.","ContentVerse (contentverse.co.in) is an India-first platform. We publish and host original work in English and Hindi, with human moderation, clear policies, and compliance with Indian law including the IT Act, 2000, IT Rules, 2021, and the Digital Personal Data Protection Act, 2023."]},{heading:"What we offer readers",paragraphs:["Readers come to ContentVerse for long-form articles they can bookmark and share — explainers, tutorials, opinion, and reporting across technology, finance, lifestyle, sports, careers, and more.","Live cricket scores, market data, and job listings sit alongside our writing as utilities. They help you stay informed, but our primary value — and what we ask search engines to rank — is original editorial content that meets our quality bar."],bullets:["Original long-form articles with cover images, author profiles, and related reads","Threaded comments, reactions (like, love, fire, clap, insightful), and tips in ₹","Reading streaks, bookmarks, and personalised recommendations for signed-in readers","Clear legal pages: Content Policy, Privacy, Terms, and Cookies"]},{heading:"What we offer creators",paragraphs:["Creators get a full studio: drafts, scheduling, SEO fields, AI writing assist, analytics, and a wallet for tips. Submissions go through human review so the public library stays high quality.","Verified creators in our Creator Program can earn through tips, featuring, and transparent dashboards — always with payout rules and tax responsibilities explained in our Terms."],bullets:["Write, schedule, and edit posts (including live edits that stay published)","AI assist for drafts, excerpts, tags, and SEO metadata","Moderation queue with approve, request changes, or reject","Tips, leaderboard, and category featuring for quality work"]},{heading:"What we believe",bullets:["Readers reward depth — not clickbait or thin AI spam.","Creators should own their audience and understand their earnings.","Moderation should be human, fast, and fair.","Advertising (including Google AdSense) must respect privacy and publisher policies.","India’s internet deserves world-class editorial tools built for local creators."]},{heading:"By the numbers",cards:[{title:"Categories",description:"Technology, AI, finance, lifestyle, sports, careers, and more — with room to grow as the community expands.",meta:"21+ topics"},{title:"Creator tools",description:"Drafts, scheduling, SEO, AI assist, analytics, tips, notifications, and a full dashboard.",meta:"All-in-one studio"},{title:"Payouts",description:"Wallet, tips, and revenue tracking in INR with clear tax and KYC expectations.",meta:"₹ native"},{title:"Trust & safety",description:"Content Policy, human moderation, report tools, and grievance contact for readers and creators.",meta:"Policy-first"}]},{heading:"Trust, ads & compliance",paragraphs:["We may show Google AdSense and other ads on eligible pages. We disclose advertising cookies in our Cookie Policy and do not sell personal data. Creators and readers can review Privacy, Terms, and Content Policy anytime from the footer.","We act as an intermediary under Indian IT law: we host user content, enforce policies, and respond to valid legal orders and user reports."]},{callout:`Questions? Write to ${f.ei} — we read every message.`}]},careers:{slug:"careers",badge:"Careers",title:"Come build ContentVerse with us",subtitle:"We’re a small, focused team shipping fast for creators across India. If you love writing, product, community, or engineering — we’d like to meet you.",sections:[{heading:"Why join ContentVerse",paragraphs:["You’ll work on a real product used by readers and writers every day — not a slide deck. We care about editorial quality, fair monetization in rupees, and tools that respect Indian creators.","We are remote-friendly within India, async-first, and serious about ownership. You will ship visible features, talk to creators, and help set the standard for long-form publishing online."]},{heading:"Open roles",cards:[{title:"Full-stack Engineer",description:"Next.js, Prisma, Postgres — ship creator-facing features end to end: editor, scheduling, payments UX, and performance. You own problems from API to UI.",meta:"Remote \xb7 India"},{title:"Community & Creator Success",description:"Onboard writers, run feedback loops, grow the Creator Program, and turn support tickets into product insights.",meta:"Remote \xb7 India"},{title:"Editorial Associate",description:"Review submissions, uphold the Content Policy, improve discoverability, and coach creators toward AdSense-quality long-form work.",meta:"Part-time \xb7 Remote"},{title:"Growth & Partnerships",description:"Help creators and partners discover ContentVerse — campaigns, campus programs, and ethical growth experiments.",meta:"Contract \xb7 India"}]},{heading:"How we work",bullets:["Async-first with clear ownership and written decisions","Ship weekly, measure what matters (quality and retention, not vanity metrics)","Creator feedback drives the roadmap","Inclusive, no-ego collaboration — respect for every teammate and creator","Compliance-aware: privacy, content policy, and Indian legal norms are part of the job"]},{heading:"What we look for",paragraphs:["We hire for craft and curiosity. You don’t need a famous resume — you need proof you can ship, write clearly, or care deeply about creators."],bullets:["Portfolio, GitHub, published writing, or community work we can review","Comfort with remote collaboration across Indian time zones","Respect for readers, copyright, and platform safety"]},{heading:"How to apply",paragraphs:[`Email ${f.ei} with the role in the subject line. Include a short note on why ContentVerse, links to your work, and your preferred start timeline. We aim to reply within two weeks.`]},{callout:`Don’t see your role? Email ${f.ei} with your portfolio or GitHub — we hire for exceptional people, not only open listings.`}]},press:{slug:"press",badge:"Press",title:"Press & media",subtitle:"Resources for journalists, partners, and creators covering ContentVerse — India’s home for long-form publishing.",sections:[{heading:"About ContentVerse",paragraphs:["ContentVerse (contentverse.co.in) is an India-first creator publishing platform focused on long-form writing, short news formats, monetization in INR, and community features like polls, tips, reactions, and leaderboards.","We combine a writer’s studio (drafts, scheduling, SEO, AI assist, analytics) with human moderation so the public library stays original and useful. Live sports scores, market data, and job listings complement articles as reader utilities — not as thin pages we ask search engines to rank.","Our policies align with Indian law (IT Act, IT Rules 2021, DPDP Act 2023) and Google AdSense publisher standards for quality content and advertising disclosures."]},{heading:"Boilerplate (short)",paragraphs:["ContentVerse is a next-generation creator platform for readers and writers — built in India for depth, design, and fair rupee payouts."]},{heading:"Boilerplate (long)",paragraphs:["ContentVerse is an India-first publishing platform where writers, journalists, and creators publish long-form articles, tutorials, and opinion in English and Hindi. The product includes editorial moderation, a Creator Program with tips and featuring, transparent analytics, and legal pages covering privacy, cookies (including Google advertising), terms, and content standards."]},{heading:"Press contact",bullets:[`Email: ${f.ei}`,"Based in India","Response within 2 business days for media queries","For partnership or creator stories, mention “Press” in the subject line"]},{heading:"Brand assets",cards:[{title:"Logo & name",description:"Use “ContentVerse” — one word, capital C and V. Do not alter the logo colours or stretch the mark.",meta:"Brand"},{title:"Product description",description:"A next-generation creator platform for readers and writers, with long-form publishing and INR monetization.",meta:"One-liner"},{title:"Founding narrative",description:"Built to give Indian creators fair tools, rupee payouts, editorial quality, and policies that respect Indian law.",meta:"Story"},{title:"Website",description:"https://contentverse.co.in — primary product and press destination.",meta:"URL"}]},{heading:"Facts at a glance",bullets:["Primary market: India (English & Hindi creators and readers)","Core product: long-form blogs, creator dashboard, tips in ₹","Trust: Content Policy, human moderation, privacy & cookie disclosures","Advertising: Google AdSense on eligible pages where configured"]},{callout:`Media kit or interview requests: ${f.ei}`}]},premium:{slug:"premium",badge:"Premium",title:"ContentVerse Premium",subtitle:"Unlock deeper analytics, priority review, and premium placement for your best work — priced fairly in rupees.",sections:[{heading:"What's included",cards:[{title:"Priority review",description:"Faster moderation queue for Premium-tagged submissions.",meta:"Creators"},{title:"Enhanced analytics",description:"30-day views, completion rate, and revenue breakdown.",meta:"Dashboard"},{title:"Premium badge",description:"Stand out on Explore, category pages, and your profile.",meta:"Visibility"},{title:"Paid posts",description:"Mark select articles as Premium for subscriber-only access.",meta:"Monetization"}]},{heading:"Pricing",paragraphs:["Premium creator plan: ₹199/month — cancel anytime.","Reader Premium (ad-light experience + exclusive posts): ₹199/month.","Tips and one-time paid posts are always available on the free plan."]},{callout:`Interested in early access? Contact ${f.ei} from your creator dashboard email.`}]},"creator-program":{slug:"creator-program",badge:"Creators",title:"ContentVerse Creator Program",subtitle:"Publish, grow, and earn — with editorial support, verification, and monetization built in. Quality over follower count.",sections:[{heading:"Who it’s for",paragraphs:["Writers, journalists, educators, and indie creators who publish original work in English or Hindi. You don’t need a huge following — consistency, originality, and usefulness matter more.","If you write explainers, tutorials, reporting, or thoughtful opinion that readers would bookmark, you belong here. We are not a home for mass AI spam, scraped posts, or clickbait farms."]},{heading:"Benefits",bullets:["Verified creator badge after approval","Tips in ₹ directly to your wallet (taxes and KYC may apply as described in Terms)","Leaderboard and category featuring for strong work","Push notifications when readers engage","AI writing assist for drafts, excerpts, tags, and SEO","Blog scheduling — set a future publish time in IST","Fair moderation with human review and clear feedback","Transparent analytics so you understand what readers finish"]},{heading:"Quality bar",paragraphs:["Indexable articles should be original and substantive — typically around 800+ words with clear structure, sourcing where needed, and no plagiarism. Finance and health topics need careful disclaimers.","Our Content Policy and Google AdSense publisher standards guide what stays live. Thin pages, duplicate posts, and prohibited categories are removed."]},{heading:"How to join",cards:[{title:"1. Create account",description:"Sign up at contentverse.co.in, complete your profile photo and bio, and choose a clear username.",meta:"Free"},{title:"2. Publish quality posts",description:"Submit at least two original articles for review. Use the editor, SEO fields, and schedule if you want a future go-live time.",meta:"Quality bar"},{title:"3. Apply for verification",description:`Email ${f.ei} with your username and links to your best posts. We review within about seven days.`,meta:"Review ~7 days"},{title:"4. Grow & earn",description:"Engage readers, earn tips, track analytics, and stay within the Content Policy to keep your badge.",meta:"Ongoing"}]},{heading:"What we expect from verified creators",bullets:["Original work you have the rights to publish","Respectful engagement in comments and community features","No harassment, hate, illegal content, or deceptive practices","Accurate profiles — no impersonation","Compliance with Terms, Privacy Policy, and Indian law"]},{heading:"Earnings & transparency",paragraphs:["Tips and wallet balances are shown in Indian Rupees. Payout timing, fees, and any tax documentation requirements are described in the dashboard and Terms of Service. We do not guarantee income; earnings depend on reader engagement and your consistency."]},{callout:`Ready to apply? Email ${f.ei} with your username after publishing your first quality posts.`}]},terms:{slug:"terms",badge:"Legal",title:"Terms of Service",subtitle:"Last updated: July 2026. By using ContentVerse (contentverse.co.in) you agree to these terms under Indian law.",sections:[{heading:"Agreement & eligibility",paragraphs:["These Terms govern access to ContentVerse, an India-first publishing platform operated for users in India and worldwide. By creating an account or using the site you accept these Terms, our Content Policy, Privacy Policy, and Cookie Policy.","You must be at least 18 years old, or use the service only with a parent or guardian’s consent where Indian law requires it. You must provide accurate registration details and keep your password secure."]},{heading:"Using the platform",bullets:["You may read, publish, comment, tip creators, and use utilities (sports scores, market data, job listings) for personal, non-abusive purposes.","You may not scrape at scale, spam, impersonate others, distribute malware, or attempt to disrupt the service.","You must comply with the Information Technology Act, 2000, applicable criminal and civil law, and our Content Policy."]},{heading:"Your content & licence",bullets:["You retain ownership of original work you publish.","You grant ContentVerse a worldwide, non-exclusive licence to host, display, distribute, and promote your content on the platform and in related marketing.","You confirm you have all rights to text, images, and media you upload, and that your content does not infringe copyright, trademark, or privacy rights.","We may remove or restrict content that violates these Terms, our Content Policy, or Indian law, including orders under the IT Act and IT Rules, 2021."]},{heading:"Payments, tips & taxes",paragraphs:["Tips and creator earnings are shown in Indian Rupees (₹). Payout methods, timelines, and fees are described in the dashboard and may change with reasonable notice.","You are responsible for any income tax, GST, or other statutory obligations on earnings. We may request KYC or tax information required by Indian payment partners or law."]},{heading:"Advertising",paragraphs:["We may display third-party advertisements, including Google AdSense, on eligible pages. Ads are subject to Google’s publisher policies and our Cookie Policy. We do not guarantee ad revenue."]},{heading:"Intermediary status",paragraphs:["ContentVerse acts as an intermediary under the Information Technology Act, 2000 and the Information Technology (Intermediary Guidelines and Digital Media Ethics Code) Rules, 2021. We provide tools for users to publish and interact; we do not pre-author every word, but we moderate reported content and enforce our policies.","We maintain a grievance redressal contact for complaints about content or accounts. Contact details appear below."]},{heading:"Limitation of liability",paragraphs:["To the extent permitted by Indian law, ContentVerse is provided on an “as is” and “as available” basis. We are not liable for indirect, incidental, or consequential damages arising from use of the service, third-party ads, or user-generated content.","Nothing in these Terms limits liability that cannot be limited under applicable law, including fraud or personal injury caused by negligence where such limits are prohibited."]},{heading:"Governing law",paragraphs:["These Terms are governed by the laws of India. Courts in India shall have exclusive jurisdiction, subject to mandatory consumer protections that apply to you."]},{callout:`Grievance & legal: ${f.ei}`}]},privacy:{slug:"privacy",badge:"Legal",title:"Privacy Policy",subtitle:"Last updated: July 2026. How ContentVerse collects, uses, and protects personal data under Indian law (including the DPDP Act, 2023).",sections:[{heading:"Who we are",paragraphs:["ContentVerse (contentverse.co.in) is a publishing platform for readers and creators. This Privacy Policy explains how we process personal data when you visit, register, publish, tip, or interact with ads on our site."]},{heading:"Information we collect",bullets:["Account details: name, email, username, profile photo, bio, and password (stored hashed)","Usage data: pages read, reading time, likes, comments, bookmarks, and device type","Device & cookies: session tokens, preferences, visitor keys, and push notification tokens","Payment-related metadata for tips and payouts (we do not store full card numbers on our servers)","Communications you send to support or grievance contacts"]},{heading:"Legal basis & purpose (India)",paragraphs:["We process personal data to provide the service you request (account, publishing, tips), to keep the platform secure, to moderate content, to send notifications you enable, and to comply with Indian law.","We process data in line with the Digital Personal Data Protection Act, 2023 (DPDP Act) and applicable rules. Where consent is required, we seek it clearly; you may withdraw consent for optional processing (such as marketing or non-essential cookies) without affecting essential service functions."]},{heading:"Advertising & Google AdSense",paragraphs:["We may use Google AdSense and related Google advertising services to show ads on eligible pages. Google and its partners may use cookies or similar technologies to serve ads based on prior visits to this site or other sites, and to measure ad performance.","Google’s use of advertising cookies is described in Google’s Privacy Policy and Ad Settings (adssettings.google.com). You can opt out of personalised ads through Google Ad Settings and control cookies via your browser and our Cookie Policy.","We do not sell your personal data to third-party advertisers. Ad partners process data as independent controllers or as described in their policies."]},{heading:"How we use data",bullets:["Authentication, personalisation, and creator analytics","Moderation, fraud prevention, and security","Notifications you opt into (email or browser push)","Legal compliance, dispute resolution, and tax/payout records"]},{heading:"Your rights",bullets:["Access and update profile information in your Dashboard","Request correction or deletion of personal data where applicable under the DPDP Act",`Contact our grievance / privacy contact at ${f.ei}`,"Disable push notifications in browser or device settings","Control non-essential cookies as described in the Cookie Policy"]},{heading:"Data retention & security",paragraphs:["We retain account and content data while your account is active and for as long as needed for legal, security, tax, and payout obligations. We use reasonable technical and organisational measures to protect data; no method of transmission is fully secure."]},{heading:"Children",paragraphs:["ContentVerse is not directed at children under 18. If you believe we have collected data from a minor without appropriate consent, contact us and we will take steps to delete it."]},{callout:`Privacy & grievance contact: ${f.ei}`}]},cookies:{slug:"cookies",badge:"Legal",title:"Cookie Policy",subtitle:"Last updated: July 2026. How ContentVerse uses cookies and similar technologies, including advertising cookies for Google AdSense.",sections:[{heading:"What are cookies?",paragraphs:["Cookies are small text files stored on your device. We also use similar technologies such as local storage and pixels. Some are essential for the site to work; others help us understand usage or show relevant ads."]},{heading:"Cookies we use",bullets:["Essential: sign-in sessions, security, load balancing, and fraud prevention","Preferences: theme (light/dark), remembered login identifier","Analytics: aggregated visit counts and reading patterns to improve the product","Visitor key: anonymous reading history for recommendations","Advertising: Google AdSense and Google advertising cookies may be set to deliver and measure ads (including personalised ads where permitted)"]},{heading:"Google advertising cookies",paragraphs:["When AdSense or Google ads are active, Google may use cookies such as the DoubleClick / IDE cookie and other advertising identifiers to show ads based on your visits to this and other websites, and to limit how often you see an ad.","You can manage ad personalisation at Google Ad Settings (https://adssettings.google.com) and learn more at Google’s advertising policies. Blocking advertising cookies may still show non-personalised ads."]},{heading:"Managing cookies",paragraphs:["You can block or delete cookies in your browser settings. Essential cookies are required for sign-in and core security; if you block them, parts of ContentVerse may not work.","Where required, we will seek consent for non-essential cookies. You may withdraw consent by clearing cookies and adjusting browser settings."]},{heading:"Third parties",paragraphs:["We use trusted providers for authentication, hosting, push delivery, analytics, and advertising (including Google). Their processing is governed by their own policies in addition to this Cookie Policy and our Privacy Policy."]},{callout:`Questions about cookies: ${f.ei}`}]},policy:{slug:"policy",badge:"Legal",title:"Content Policy",subtitle:"Last updated: July 2026. Editorial standards for publishing on ContentVerse — aligned with Indian law and Google AdSense publisher policies.",sections:[{heading:"Purpose",paragraphs:["ContentVerse is built for original, useful long-form writing. This Content Policy protects readers, creators, and the integrity of the platform. It applies to articles, comments, profiles, reels captions, and other user-generated content."]},{heading:"We welcome",bullets:["Original essays, reporting, tutorials, and opinion with clear sourcing","Respectful debate and constructive criticism","Proper attribution for quotes, images, data, and third-party material","Content in English or Hindi that adds genuine value for Indian and global readers"]},{heading:"Not allowed",bullets:["Hate speech, harassment, threats, or content that incites violence","Plagiarism, copyright infringement, or mass AI-generated spam without human editorial value","Illegal content under Indian law, including child sexual abuse material, malware, or instructions for serious crime","Misleading health, medical, or financial claims without evidence and appropriate disclaimers","Explicit adult content, gratuitous violence, or content that exploits minors","Impersonation, phishing, or deceptive practices","Content that violates Google AdSense / Google Publisher Policies (including dangerous, deceptive, or prohibited content categories)"]},{heading:"Editorial quality (AdSense-ready)",paragraphs:["Articles must be original, substantive, and useful. We expect a minimum of roughly 800 words for standard indexable posts (about four minutes of reading time). Thin pages, doorway pages, and keyword-stuffed content are not accepted.","Mass-produced AI content without meaningful human editing, duplicate posts across categories, and scraped third-party articles are removed. Finance and health topics require careful sourcing and disclaimers (not personalised advice).","Live scores, stock widgets, and job listings are reader utilities; they do not replace original editorial writing as our primary content."]},{heading:"Moderation & IT Rules, 2021",paragraphs:["Submissions may be pending review before going live. Moderators can approve, request edits, or reject work that breaks this policy.","As an intermediary under the IT Act, 2000 and IT Rules, 2021, we act on valid legal orders and on user reports of unlawful content. Repeat violations may lead to suspension, removal from the Creator Program, or account termination."]},{heading:"Reporting & grievance",paragraphs:[`Report policy violations or unlawful content using in-product report tools or email ${f.ei}. We aim to acknowledge grievances promptly and take action consistent with Indian law and this policy.`]},{callout:`Report concerns: ${f.ei}`}]}};function i(a){return a.map(a=>({...a,paragraphs:a.paragraphs?.map(f.s5),bullets:a.bullets?.map(f.s5),callout:a.callout?(0,f.s5)(a.callout):a.callout,cards:a.cards?.map(a=>({...a,description:(0,f.s5)(a.description),title:(0,f.s5)(a.title),meta:a.meta?(0,f.s5)(a.meta):a.meta}))}))}let j=["about","careers","press","premium","creator-program","terms","privacy","cookies","policy"];async function k(){if((0,e.isDatabaseConfigured)()){for(let a of g){let b=h[a],c=j.includes(a);await e.prisma.sitePage.upsert({where:{slug:a},create:{slug:a,title:b.title,subtitle:b.subtitle,badge:b.badge??null,sections:b.sections},update:c?{title:b.title,subtitle:b.subtitle,badge:b.badge??null,sections:b.sections}:{}})}for(let a of(await e.prisma.sitePage.findMany({select:{id:!0,sections:!0}}))){let b=Array.isArray(a.sections)?a.sections:[];JSON.stringify(b).includes(f.WL)&&await e.prisma.sitePage.update({where:{id:a.id},data:{sections:i(b)}})}}}async function l(a){if(!g.includes(a))return null;let b=h[a];if(!(0,e.isDatabaseConfigured)())return{...b};await k();let c=await e.prisma.sitePage.findUnique({where:{slug:a}});if(!c)return{...b};let d=function(a){let b=i(Array.isArray(a.sections)?a.sections:[]);return{slug:a.slug,title:a.title,subtitle:a.subtitle??"",badge:a.badge??void 0,sections:b,updatedAt:a.updatedAt.toISOString()}}(c);return 0===d.sections.length?{...b,updatedAt:d.updatedAt}:d}let m=(0,d.cache)(l);async function n(a,b){return(0,e.isDatabaseConfigured)()?(await k(),e.prisma.sitePage.update({where:{slug:a},data:{title:b.title,subtitle:b.subtitle,badge:b.badge,sections:b.sections}})):null}},87431:(a,b,c)=>{c.d(b,{UR:()=>g,WL:()=>e,ei:()=>d,s5:()=>f,v7:()=>h});let d="writewith@contentverses.in",e="writewith@contentveres.in";function f(a){return a.replace(/writewith@contentveres\.in/gi,d)}let g="+919411441937",h="+91 94114 41937"}};